onRowSelected:
{{
  (async () => {
    // 1. Mantém a sua lógica atual
    await storeValue('modalContexto', {
      acaoTipo: "EDITAR",
      acaoBotao: "ATUALIZAR"
    });

    // --- NOVA LINHA AQUI ---
    // Garante que ao trocar de tutor, voltamos para a primeira aba
    await storeValue('abaAtiva', 'Info Cadastral'); 
    // -----------------------

    // 2. Chama a função de inatividade
    JSutils.resetInactivityTimer();
  })()
}}

customColumn1.onClick:
{{
  (async () => {
    // 1. Desabilita visualmente o Container Tutor e habilita o de Pets
    await storeValue("telaAtiva", "PETS");

    // 2. Define o contexto (para saber qual tutor estamos visualizando)
    await storeValue('modalContexto', {
      ...appsmith.store.modalContexto,
      entidade: 'PET',
      acaoTipo: "EDITAR",
      tutorID: TableTutor.selectedRow?.prop001_id,
      tutorNome: TableTutor.selectedRow?.prop001_nome
    });

    // 3. Opcional: Atualizar a lista de pets do banco
    // await SelectPets.run();

    // 4. Reset de segurança (agora funciona sem pular aba!)
    // resetWidget("ContainerPets", true);

    JSutils.resetInactivityTimer();
  })()
}}
